function solve(nums) {
    let maxSum = 0;
    const n = nums.length;

    // Iterate all possible masks for A and B (each bit represents if the element is in A or B)
    // Since each element can be in A, B, or C, we can represent the state with two bits per element
    // But with n up to 19, it's impractical to iterate all 3^19 possibilities
    // Instead, we can iterate all possible non-empty B and compute XOR(A) + AND(B) + XOR(C)
    // But even that is O(2^n), which is manageable for n=19 (2^19 = 524288)

    // Precompute prefix XOR and suffix XOR arrays to optimize XOR(A) and XOR(C) calculations
    const prefixXOR = new Array(n + 1).fill(0);
    const suffixXOR = new Array(n + 1).fill(0);

    for (let i = 0; i < n; i++) {
        prefixXOR[i + 1] = prefixXOR[i] ^ nums[i];
    }

    for (let i = n - 1; i >= 0; i--) {
        suffixXOR[i] = suffixXOR[i + 1] ^ nums[i];
    }

    // Iterate all possible non-empty B subsets (represented as bitmask)
    for (let mask = 1; mask < (1 << n); mask++) {
        let andB = ~0; // Initialize with all bits set (for AND)
        let countB = 0;
        let indicesB = [];

        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                andB &= nums[i];
                countB++;
                indicesB.push(i);
            }
        }

        // Now, for this B, we need to split the remaining elements into A and C
        // The remaining elements are those not in B
        // We can split them into A (left of B) and C (right of B)
        // Or any other split, but to maximize, we can consider all possible splits

        // To optimize, we can consider that the best split is when A is the prefix up to first B element, and C is the suffix after last B element
        // But this might not always be the case, so we need to check all possible splits

        // Alternatively, for each B, we can consider all possible splits of the remaining elements into A and C
        // But this would be O(2^(n - countB)), which is not feasible for n=19

        // Another approach: for the remaining elements, the best XOR(A) + XOR(C) is equal to XOR(all remaining) because XOR is associative and commutative
        // So, the sum XOR(A) + XOR(C) is the same as XOR(A + C) = XOR(remaining)
        // So, we can compute XOR(remaining) = totalXOR ^ XOR(B)
        // But this is not correct because XOR(A) + XOR(C) is not necessarily XOR(A + C)
        // For example, if A = [a], C = [b], then XOR(A) + XOR(C) = a + b, but XOR(A + C) = a ^ b

        // So, the previous approach is invalid

        // Instead, we need to find the best split of the remaining elements into A and C to maximize XOR(A) + XOR(C)
        // For the remaining elements, we can compute prefix XOR and suffix XOR

        const remaining = [];
        for (let i = 0; i < n; i++) {
            if (!(mask & (1 << i))) {
                remaining.push(nums[i]);
            }
        }

        const m = remaining.length;
        const remPrefixXOR = new Array(m + 1).fill(0);
        const remSuffixXOR = new Array(m + 1).fill(0);

        for (let i = 0; i < m; i++) {
            remPrefixXOR[i + 1] = remPrefixXOR[i] ^ remaining[i];
        }

        for (let i = m - 1; i >= 0; i--) {
            remSuffixXOR[i] = remSuffixXOR[i + 1] ^ remaining[i];
        }

        let maxXorSum = 0;

        // Try all possible splits of remaining into A and C
        for (let split = 0; split <= m; split++) {
            const xorA = remPrefixXOR[split];
            const xorC = remSuffixXOR[split];
            const currentSum = xorA + xorC;
            if (currentSum > maxXorSum) {
                maxXorSum = currentSum;
            }
        }

        const total = maxXorSum + andB;
        if (total > maxSum) {
            maxSum = total;
        }
    }

    // Also consider the case where B is empty (all elements in A and/or C)
    // Then, the sum is XOR(A) + XOR(C), which is the same as XOR(nums) if we split into A and C optimally
    // To maximize XOR(A) + XOR(C), we can split into any A and C such that the sum is maximized
    // This is equivalent to finding a split where XOR(A) + XOR(C) is maximized
    // We can compute this using prefix and suffix XOR

    let maxEmptyB = 0;
    for (let split = 0; split <= n; split++) {
        const xorA = prefixXOR[split];
        const xorC = suffixXOR[split];
        const currentSum = xorA + xorC;
        if (currentSum > maxEmptyB) {
            maxEmptyB = currentSum;
        }
    }

    if (maxEmptyB > maxSum) {
        maxSum = maxEmptyB;
    }

    return maxSum;
}

